var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_QM","text":{"KOREA":"아아…….","JPN":"ああ……","ENG":"Ah...","TWN":"啊啊……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_QM","text":{"KOREA":"두려움에 떠는 연약한 악기들의 소음이 들려 오는군요.","JPN":"恐怖に震えるか弱い楽器の雑音が聞こえてきますね。","ENG":"I hear the noise of pathetic instruments quivering from dread.","TWN":"我聽到戰兢害怕的怯弱樂器發出的噪音。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_QM","text":{"KOREA":"결혼이란 이토록 덧없이 요란한 연주인 것을.","JPN":"結婚とはこのようにはかなくも騒々しい演奏なのです。","ENG":"Marriage is but a strident score of a meaningless performance.","TWN":"婚禮就是一場短暫又喧鬧的演奏。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"저건 또 뭔데!","JPN":"何だ、あれは！？","ENG":"Who's that?!","TWN":"她又是怎麼回事！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"우와… 엄청 예뻐!","JPN":"うわ……すごくきれい！","ENG":"Whoa... She's beautiful!","TWN":"哇……好漂亮喔！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"지금 그게 문제야?!","JPN":"今それが問題か！？","ENG":"That's what you're fixated on?!","TWN":"那是重點嗎？！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_QM","text":{"KOREA":"조화롭지 못한 것들의 하모니라.","JPN":"調和の取れないものたちのハーモニーですか。","ENG":"A discordance of inharmonious beings.","TWN":"不和諧樂器的和聲，"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_QM","text":{"KOREA":"결혼하기를 두려워하는 소리가 이곳까지 울리는군요.","JPN":"結婚を恐れている音がここまで響いていますね。","ENG":"The fear of marriage echoes through the room.","TWN":"害怕結婚的聲音連這裡都聽得到呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"뭐, 뭘 두려워해?","JPN":"は？　何を恐れるって？","ENG":"F-fear? Why?","TWN":"害，害怕什麼？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_QM","text":{"KOREA":"생각해 보시죠.","JPN":"考えてみましょう。","ENG":"Consider this.","TWN":"想想看吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_QM","text":{"KOREA":"결혼을 해 얻는 유익이라곤 홀로 쓰던 방을 둘이 같이 나눠 써야하는 것뿐.","JPN":"結婚をして得られるものといえば一人で使っていた部屋を二人で使うということのみ。","ENG":"The only benefit one gains from marriage is sharing a room between two people.","TWN":"結婚的唯一好處，就是房間從個人房變成雙人房。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_QM","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_QM","text":{"KOREA":"환상을 억지로 현실에 끼워 맞춘 결혼식 준비로 언성만 높아지고, 예식이 진행되는 그 한순간을 위해 청춘을 다 바쳐 모은 돈을 날려 버리고.","JPN":"幻想を無理やり現実に当てはめた結婚式、その準備のために言い合いばかりが多くなり、式が行われるその瞬間のために青春をすべて捧げて集めた貯金を使い果たす。","ENG":"Wedding preparations, where one attempts to fit fantasy into a mold called reality, cause distress and screaming. The short-lived ceremony causes the loss of one's entire savings.","TWN":"婚禮是硬將幻想帶入現實，在籌備過程只會使音量越來越大，而婚禮就只有短短的一天，卻必須付出青春與積蓄。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_QM","text":{"KOREA":"함께 살며 결국 사랑도 뭣도 잊은 채 오직 의리와 미운 정으로만 살아가는 부부의 모습을 진정 원하시는 건 아니겠죠.","JPN":"共に暮らしながら結局は愛も何も忘れ、過ぎた時間から生じた義理の感情、ただそれだけで生きる夫婦の姿を本当に望んでいるわけではないでしょう。","ENG":"Eventually, the bride and groom forget love, romance, and happiness and settle for the life of a wife and husband who only stay together for the sake of not creating a hassle.","TWN":"結婚後，愛情在生活中消磨殆盡，只剩下責任義務與厭惡，這應該不是你們想要的吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_QM","face":"UNIT_DESPAIR"},"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_QM","text":{"KOREA":"모든 사실을 알게 된 신혼 부부가 맞닥뜨릴 절망을 떠올려 보신 적 있으신가요?","JPN":"すべての事実を知った新婚夫婦が直面する絶望を考えてみたことがありますか？","ENG":"Have you considered the despair newlyweds would feel after learning all this?","TWN":"你有想過，發現這個真相的新婚夫妻會有多絕望嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_QM","face":"UNIT_IDLE"},"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_QM","text":{"KOREA":"미리 이 사실을 알았다면, 결혼을 하지 않았다면 좋았을걸, 후회하는 목소리가 정말 들리지 않으시나요?","JPN":"もしこの事実を前もって知ってさえいれば、結婚などしなければよかったと、後悔する声が聞こえませんか？","ENG":"Do you not hear their miserable voices wishing they knew the consequences of marriage before making a lifelong commitment?","TWN":"早知如此我才不會結婚，你沒聽到他們後悔的發言嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_QM","face":"UNIT_IDLE"},"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"뭐 저리 부정적이야?","JPN":"なんでそんなに否定的なんだ？","ENG":"Why is she so negative?","TWN":"她怎麼這麼消極？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"정말! 꼭 라우라 같아!","JPN":"本当にね！　ラウラそっくり！","ENG":"Yeah! Like you, Laura!","TWN":"真的欸！就跟蘿拉一樣！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"시끄러워!","JPN":"うるさいっ！","ENG":"Shut up!","TWN":"你閉嘴！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_QM","text":{"KOREA":"저는… 결혼의 두려움이 낳은 비명이자 파멸의 신부.","JPN":"私は……結婚の恐怖が産んだ悲鳴であり破滅の花嫁。","ENG":"I... am the destructive bride, the culmination of humans' fear of marriage.","TWN":"我是……因為恐婚而產生哀號，我是幻滅的新娘。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_QM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_FAKE","text":{"KOREA":"결혼으로 파국이 확정될 이 세상 모든 신랑, 신부들을 구하고자 왔습니다.","JPN":"結婚で悲劇が確定してしまった、この世界の全ての新郎新婦を救うためにやってきました。","ENG":"I am here to save all brides and grooms from the inevitable ruins of marriage.","TWN":"我是來拯救所有要進入婚姻墳墓的新郎、新娘。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"저 사람! 내가 만든 드레스를 입고 있어!","JPN":"あの人！　私が作ったドレスを着てる！","ENG":"Wait! She's wearing the dress I made!","TWN":"那個人！穿的是我做的婚紗！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L32_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그러네?! 이 사람도 그럼 마법으로 만들어진 건가 봐!","JPN":"本当だ！　じゃあ、あの人も魔法で作られたってことだね！","ENG":"You're right! Then she must also be made of magic!","TWN":"對欸？！那看來她也是魔法製造出來的仿冒品！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"하지만, 애초에 저런 위험한 저주를 디저트에 걸었을 리가 없잖아?","JPN":"しかし、そもそもあんな危険な呪いをデザートにかけるわけがないだろう？","ENG":"But I would never cast such a dangerous curse on desserts in the first place!","TWN":"可是，我怎麼可能對甜點施那種危險的咒語？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"혹시… 결혼에 대해 어떻게 생각해?","JPN":"もしかして……ラウラ、結婚についてどう考えてるの？","ENG":"Uh... What is your opinion on marriage?","TWN":"那個……蘿拉，你對婚姻有什麼想法？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"뭐? 그야… 해, 해본 적이 없으니까 나도 모르지!","JPN":"うん？　それは……し、したことがないのにわかるわけがないだろう！","ENG":"Huh? Well... I-I don't know! I've never been married!","TWN":"蛤？那個……我，我又沒結過婚，我怎麼知道！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"네게서 두려움을 느끼고 탄생했을 수도 있어.","JPN":"あなたから恐れを感じて誕生してしまったかのかもしれないわ。","ENG":"It might've been the result of your fear.","TWN":"她可能是因為你的恐懼才產生的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"웃기는 소리! 베아트릭스는 두려움을 모르는 가문이라고!","JPN":"笑わせるな！　ベアトリクス家は恐れなど知らない一門だ！","ENG":"Hah! We Beatrixes fear nothing!","TWN":"開什麼玩笑！貝阿朵莉絲家族的字典裡沒有恐懼這二個字！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"……물론 가끔 부모님이 싸우실 땐 성 인테리어를 다시 해야 했지만.","JPN":"……もちろん、両親が喧嘩して城の内装をやり直さなくてはならない時もあったが。","ENG":"...I mean, we did have to redo our castle interior after my parents fought.","TWN":"……當然，我父母偶爾會吵吵架，吵完可能就需要重新裝修城堡……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"역시 베아트릭스 가문은 성질이 장난이 아니었구나…….","JPN":"やっぱりベアトリクス家の気性は半端じゃないんだね……","ENG":"I knew it... the Beatrixes have a fierce temper...","TWN":"貝阿朵莉絲家族的脾氣果然不是開玩笑的……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"여러분?","JPN":"皆さん？","ENG":"Excuse me.","TWN":"大家？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP"},{"id":"L46_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"말씀 나누는 중에 죄송한데, 조금 위험해 보여서요.","JPN":"お話し中にすみませんが、少し危なそうでしたので。","ENG":"Sorry to interrupt, but that looks a bit dangerous.","TWN":"抱歉打斷你們的談話，不過現在情況好像有點危險。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"저 파멸의 신부라는 분… 조금씩 이쪽으로 올 때마다 주변이 난장판 되는데요……?","JPN":"あの破滅の花嫁という方……こちらに移動するたびに周りが大変なことになってますよ……？","ENG":"That \\"destructive bride\\"... She's wreaking havoc around her on her way here...","TWN":"那個叫幻滅新娘的……每往這邊移動一點，周圍就會亂成一團……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"앗! 정말이잖아?","JPN":"あっ！　本当だ！","ENG":"Huh? She's true!","TWN":"哇！真的欸！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"심지어 점점 더 심해져!","JPN":"それにだんだん酷くなってる！","ENG":"And it's getting worse!","TWN":"而且還越來越嚴重！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_FAKE","text":{"KOREA":"여러분을 구원해야 하나, 협조하지 않는다면 억지로라도 구해낼 수밖에 없죠.","JPN":"皆さんを救わなくてはなりませんが、協力していただけないなら無理やりにでも救うしかありません。","ENG":"You will all be saved. But if you do not comply, I shall make it happen one way or another.","TWN":"我必須拯救各位，若不乖乖配合，那我只好強行拯救。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_FAKE","text":{"KOREA":"모두… 진정한 행복을 찾아 결혼으로부터 벗어나세요.","JPN":"皆さん……本当の幸せを求めて、結婚から抜け出してください。","ENG":"Seek true happiness... Escape from the ruinous grasp of marriage.","TWN":"大家……都去尋找真正的幸福，走出婚姻的墳墓吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"앗! 공격이 안 먹혀!","JPN":"あっ！　攻撃が効かない！","ENG":"No! My attacks aren't working!","TWN":"可惡！攻擊沒效！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L8_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"파이어 볼! 파이어 볼!","JPN":"ファイヤボール！　ファイヤボール！","ENG":"Fireball! Fireball!","TWN":"火焰球！火焰球！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ONLY_YUNA_HYPER_ATTACK_START"},{"id":"L9_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"마법도 소용없는 것 같아!","JPN":"魔法も効かないみたい！","ENG":"I don't think magic works on her!","TWN":"魔法好像也不管用！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"더 두고 봤다간 카페가 난장판이 되겠어!","JPN":"このままじゃカフェが大変なことになってしまうわ！","ENG":"We have to do something, or the cafe's going to get wrecked!","TWN":"她再繼續下去，咖啡廳就要毀啦！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"그 꼴은 더 못 봐! 어떻게든 저걸 막아야……!","JPN":"そんなこと許さん！　どうにかしてあれを止めなければ……！","ENG":"I won't let that happen! We have to stop those–","TWN":"我不准她搞破壞！無論如何都要阻止她……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"아까부터 영문 모를 소리만 늘어놓으시는군요.","JPN":"さっきから訳のわからないことばかりおっしゃってますね。","ENG":"You've been talking nonsense ever since you opened your mouth.","TWN":"從剛才就一直在說些危言聳聽的話。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP"},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_FAKE","text":{"KOREA":"음? 당신은…….","JPN":"うん？　あなたは……","ENG":"Hmm? You are...","TWN":"嗯？你是……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_FAKE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"이 피로연의 주인공이에요.","JPN":"この披露宴の主人公です。","ENG":"The heroine of this ceremony.","TWN":"這場婚宴的主角。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"사랑하는 그이를 발 밑에 꿇려……","JPN":"愛する彼を足元に跪かせ……","ENG":"I was hoping to make my beloved kneel under my foot...","TWN":"我滿心期待著，讓心愛的人跪在我腳下……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"빨래를 갤 수 있도록 채찍질하는 것에 희망을 품고 기다리고 있었건만…….","JPN":"洗濯物を畳むように鞭打つことを夢見て待っていましたが……","ENG":"And whip him until he properly folds the clothes...","TWN":"再用鞭子抽他叫他把衣服折好……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"더 이상의 방해는 용납할 수 없어요.","JPN":"これ以上の妨害は許せません。","ENG":"I will not allow any more interruptions.","TWN":"我不准你擾亂我的婚禮。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_FAKE","text":{"KOREA":"……불쌍한 사람이로군요.","JPN":"……哀れな人。","ENG":"...You poor soul.","TWN":"……真是可憐。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_FAKE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_FAKE","text":{"KOREA":"다가올 파멸의 속삭임이 들리지 않으신가 보죠?","JPN":"迫りくる破滅の囁きが聞こえないのですね？","ENG":"Do you not hear the looming whispers of destruction?","TWN":"你沒聽到即將到來的幻滅在低語嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"그런 소리는 모르겠고… 비명과 신음으로 범벅이 될 찬란한 미래만 그려지네요.","JPN":"そんな囁きなんて知らない……悲鳴とうめき声だらけのまばゆい未来しか描けません。","ENG":"Whispers? I only see a bright future filled with screams and moans.","TWN":"我沒聽到……我只聽到哀嚎和呻吟聲在描繪著美好的未來"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_FAKE","text":{"KOREA":"당신에겐 사랑이 없군요.","JPN":"……あなたには愛がないのですね。","ENG":"There is no love within you.","TWN":"原來你不知道什麼是愛。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"내 사랑은 오직 나만이 알 수 있답니다.","JPN":"私の愛は私だけが理解できるのです。","ENG":"My love is not for you to see.","TWN":"我的愛唯有我自己知道。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"그분을 향한 충성스러운 내 사랑을 모독하지 마세요.","JPN":"彼に向けた忠実な愛を侮辱しないでほしいですね。","ENG":"You insult my loyal love towards him.","TWN":"我不准你侮辱我對他忠誠的愛。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"내가 죽고, 다시 태어나게 되더라도 오직 그분만을 향해 살아갈 저의 애정이 우스워 보이시나요?","JPN":"死んでまた生まれ変わっても、ただ彼だけのために生きようとする私の愛情が滑稽に見えるとでも？","ENG":"Do you consider my love a joke? Even if I die and am reborn, I will only live to serve him.","TWN":"我生是他的人，死是他的鬼，我只為他而活，這樣的愛很可笑嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_FAKE","text":{"KOREA":"묘한 말씀을 하시네요. 신부라기보다는 꼭 종에 가깝게 들립니다만.","JPN":"おかしなことを言いますね。花嫁というよりは僕に近いように聞こえますが。","ENG":"An odd expression. It sounds as if you are more of a servant rather than a bride.","TWN":"真是奇妙的愛，聽起來你比較像是僕人而不是新娘。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_FAKE","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"언제든 주인을 발 아래 엎드리게 할… 그래요. 충성스러운 인형이라면 정확하겠군요.","JPN":"いつでも主人を足元に跪かせてあげられる……そう、忠実な人形という表現が適切でしょう。","ENG":"...Well, then I would be a loyal puppet, always ready to step on my master.","TWN":"隨時可以把主人踩在腳下的……沒錯，正確來說是忠誠的木偶。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"당신은 사랑에 대해 조금도 알지 못해요.","JPN":"あなたは愛について少しもわかっていません。","ENG":"You don't know anything about love.","TWN":"你根本不知道什麼是愛。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"사랑의 힘을 모르는 당신은…… 정말 불쌍한 사람이로군요.","JPN":"愛の力を知らないあなたは……本当に哀れな人ですね。","ENG":"So oblivious to the power of love... I pity you.","TWN":"你真是可憐人……因為你不知道愛的力量。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_FAKE","text":{"KOREA":"사랑, 사랑이라.","JPN":"愛、愛ね。","ENG":"Love. Love...","TWN":"你說愛？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_FAKE","text":{"KOREA":"그 사랑이 어디까지 진심인지…… 절 막아낼 수 있다면 조금은 인정해드리도록 하죠.","JPN":"その愛がどこまで本物なのか……私を止められたら少しは認めてあげましょう。","ENG":"We shall see how true your love is. You will have my respect, if you can stop me, that is.","TWN":"那份愛到底有多少真心……若你能阻止我，那我就認同你的愛。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"둘 다 너무 진지해!","JPN":"二人ともすごく真剣！","ENG":"They're both too serious about this!","TWN":"她們會不會演得太認真！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_WEDDING_FAKE","face":"UNIT_SERIOUS"},"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"쉿. 지금은 저 둘이 싸우게 내버려두는 게 좋겠어.","JPN":"シッ。今はあの二人を戦わせておく方がいいわ。","ENG":"Shh. It's best to leave those two to fight among themselves.","TWN":"噓，現在最好讓她們二個打起來。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CONDUCT_HARMONY_WEDDING_FAKE","face":"UNIT_SERIOUS"},"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그러다 보면 기회가 생길 거야.","JPN":"そうしているうちにチャンスがあるはずよ。","ENG":"We'll get our chance.","TWN":"那我們說不定會有機可趁。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CONDUCT_HARMONY_WEDDING_FAKE","face":"UNIT_SERIOUS"},"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"하지만 우리가 아무리 공격해도 먹히질 않았잖아?","JPN":"でも、わたしたちがいくら攻撃しても通用しなかったよ？","ENG":"But none of our attacks worked!","TWN":"可是我們的攻擊又沒用？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CONDUCT_HARMONY_WEDDING_FAKE","face":"UNIT_SERIOUS"},"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"바쁘신 와중에 죄송하지만, 먹히는 것 같아요.","JPN":"お忙しいところすみませんが、通用したみたいですよ。","ENG":"Sorry to bother you again, but, I do think it worked.","TWN":"抱歉又打斷你們，好像是有用的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LENI_NPC_SUPPLEMENT_GIRL","text":{"KOREA":"냠.","JPN":"もぐもぐ。","ENG":"*Nom*","TWN":"嗯～～"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LENI_NPC_SUPPLEMENT_GIRL","text":{"KOREA":"너무 맛있어요! 한 개 더 주세요!","JPN":"すっごくおいしい！　もう一つください！","ENG":"It's yummy! Can I have another one?","TWN":"好好吃喔！我要再一塊！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L46_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"하트 포인트가 쌓일수록 걸음이 늦춰지고 있더라고요. 흥미로운 설정이에요.","JPN":"ハートポイントが集まるほど、あの方の歩みが遅くなっています。おもしろい設定ですね。","ENG":"The more Heart Points there are, the slower her footsteps are. It's an interesting idea.","TWN":"累積越多愛心點數，她的腳步就會變得越慢，真是有趣的設定。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"앗! 진짜 하트 포인트가 거의 다 찼잖아?!","JPN":"あ！　ほんとだ。ハートポイントがほぼいっぱいだよ！？","ENG":"Oh! The Heart Points are almost full!","TWN":"哇！愛心點數真的都快集滿咧？！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"우리 싸움을 지켜보면서 시켜 먹었나 봐!","JPN":"私たちの戦いを見ながら食べてたんだね！","ENG":"She must've eaten them while watching us fight!","TWN":"看來大家都一邊看我們打架一邊吃甜點！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"연극은 이제 끝내자.","JPN":"劇はもう終わりにしよう。","ENG":"The play ends now.","TWN":"鬧劇就到此為止吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"드레스들의 난동이라면 이제 지긋지긋해!","JPN":"ドレスの乱闘騒ぎなんてもうたくさんだ！","ENG":"I'm sick and tired of all the mess by these dresses!","TWN":"我已經受夠這場婚紗之亂！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};